8032	[Degreewise section identification of the {\v C}ech backbone]
8033	  \label{lem:pushPull_eval_prod_iso}
8034	  \lean{AlgebraicGeometry.pushPull_eval_prod_iso}
8035	  \uses{lem:pushPull_sigma_iso, lem:pushPull_leg_sections,
8036	    lem:evaluation_preserves_products_mathlib}
8037	  For an open \(V \subseteq X\) and every degree \(p\) there is an isomorphism
8038	  \[
8039	    \Gamma\bigl(V,\, \operatorname{pushPullObj}\mathcal{F}\,Y_p\bigr)
8040	      \;\cong\;
8041	    \prod_{\sigma : \mathrm{Fin}(p+1) \to I}
8042	      \Gamma\bigl(\operatorname{coverInterOpen}\mathcal{U}\,\sigma \cap V,\, \mathcal{F}\bigr).
8043	  \]
8044	\end{lemma}
8045	\begin{proof}
8046	  \uses{lem:pushPull_sigma_iso, lem:pushPull_leg_sections,
8047	    lem:evaluation_preserves_products_mathlib}
8048	  Combine the product decomposition of the backbone push--pull object
8049	  (Lemma~\ref{lem:pushPull_sigma_iso}), \(\operatorname{pushPullObj}\mathcal{F}\,Y_p \cong
8050	  \prod_\sigma \operatorname{pushPullObj}\mathcal{F}\,(\operatorname{Over.mk} j_\sigma)\),
8051	  with the fact that the section (evaluation-at-\(V\)) functor on \(X.\mathrm{Modules}\)
8052	  preserves products (Lemma~\ref{lem:evaluation_preserves_products_mathlib}): \(\Gamma(V,
8053	  \prod_\sigma N_\sigma) \cong \prod_\sigma \Gamma(V, N_\sigma)\). This reduces the
8054	  left-hand side to \(\prod_\sigma \Gamma\bigl(V, \operatorname{pushPullObj}\mathcal{F}\,
8055	  (\operatorname{Over.mk} j_\sigma)\bigr)\), and the per-leg section identification
8056	  (Lemma~\ref{lem:pushPull_leg_sections}) rewrites each factor as \(\Gamma(U_\sigma \cap V,
8057	  \mathcal{F})\).
8058	\end{proof}
